<style>:root{color-scheme:light;--ink:#14243a;--muted:#5c6b7c;--paper:#f7f9fc;--card:#fff;--line:#dce4ee;--primary:{{ $branding['primary_colour'] ?? '#175cd3' }};--secondary:{{ $branding['secondary_colour'] ?? '#0e9384' }};--danger:#b42318}*{box-sizing:border-box}body{margin:0;background:var(--paper);color:var(--ink);font:16px/1.55 system-ui,-apple-system,"Segoe UI",sans-serif}a{color:var(--primary)}.wrap{width:min(1120px,calc(100% - 2rem));margin:auto}.site-header{background:rgba(255,255,255,.96);border-bottom:1px solid var(--line)}.nav{min-height:72px;display:flex;align-items:center;justify-content:space-between;gap:1rem}.brand{display:flex;align-items:center;gap:.75rem;color:var(--ink);font-weight:800;text-decoration:none}.brand img{max-height:38px;max-width:170px}.button,button{display:inline-flex;align-items:center;justify-content:center;border:0;border-radius:.65rem;background:var(--primary);color:#fff;padding:.72rem 1.05rem;font:inherit;font-weight:700;text-decoration:none;cursor:pointer}.button.secondary{background:#fff;color:var(--primary);border:1px solid var(--line)}main{min-height:calc(100vh - 145px)}.hero{padding:5rem 0 4rem;background:linear-gradient(135deg,#eef5ff 0%,#f5fffc 100%)}.hero-grid,.two-col{display:grid;grid-template-columns:1.2fr .8fr;gap:3rem;align-items:center}.eyebrow{color:var(--secondary);font-weight:800;letter-spacing:.09em;text-transform:uppercase;font-size:.76rem}h1{font-size:clamp(2.25rem,5vw,4.5rem);line-height:1.02;letter-spacing:-.045em;margin:.65rem 0 1.25rem}h2{font-size:clamp(1.5rem,3vw,2.1rem);line-height:1.2}p{color:var(--muted)}.actions{display:flex;gap:.8rem;flex-wrap:wrap;margin-top:1.5rem}.panel,.feature{background:var(--card);border:1px solid var(--line);border-radius:1rem;padding:1.5rem;box-shadow:0 14px 40px rgba(20,36,58,.07)}.features{padding:4rem 0}.feature-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem}.feature h3{margin-top:0}.form-shell{width:min(480px,calc(100% - 2rem));margin:4rem auto}.field{